import React, { useCallback, useMemo, useState } from 'react';
import {
  LinPageLayout,
  LinReportPrintScopeModal,
  LinReportTableConfigModal,
  fetchReportPagesInBatches,
  loadErpReportDisplayConfig,
  resolveReportCharts,
  saveErpReportDisplayConfig,
  useCatalogTableBusy,
  type ErpReportDisplayConfig,
  type ReportPrintScope,
} from '@linm-soft-org/linm-web-common-components';
import type { ReportChartOptionDto } from '../../services/kt/models';
import type { LedgerChartData } from './buildLedgerChartData';
import { LedgerReportChartModal, type LedgerReportChartModalLabels } from './LedgerReportChartModal';
import { ReportPrintSummary, type ReportPrintFilterLine } from './ReportPrintSummary';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import { isReportChartsEnabled } from '../../utils/erpReportChartPrefs';
import { clientReportRowNo } from '../../utils/clientReportPagination';
import { runErpReportPrintAfterPaint } from '../../utils/runErpReportPrintAfterPaint';
import erp from '../../styles/erpPage.module.css';
import type { AggregateReportConfigLabels } from './ClientPagedAggregateReportShell';

export type ServerPagedAggregateReportShellProps<T> = {
  testIdPrefix: string;
  pageId: string;
  title: string;
  listTitle: string;
  titleIconClass: string;
  emptyMessage: string;
  filterItems: Array<{ testId: string; content: React.ReactNode }>;
  items: T[];
  totalCount: number;
  page: number;
  pageSize: ListPageSize;
  hasApplied: boolean;
  loading: boolean;
  pageLoading?: boolean;
  onRefresh: () => void;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: ListPageSize) => void;
  onConfigSaved?: (next: ErpReportDisplayConfig, prev: ErpReportDisplayConfig) => void;
  printFilterLines: ReportPrintFilterLine[];
  allowedCharts: ReportChartOptionDto[];
  reportChartData: LedgerChartData | null;
  chartLabels: LedgerReportChartModalLabels;
  configLabels: AggregateReportConfigLabels;
  fetchPrintPage: (targetPage: number, batchSize: number) => Promise<T[]>;
  /** Parity Sổ cái — grid row menu hint in list title. */
  listRowMenuHelp?: boolean;
  children: (
    rows: T[],
    ctx: {
      rowNo: (index: number) => number;
      onPrint: () => void;
      onChart: () => void;
      canChart: boolean;
    },
  ) => React.ReactNode;
};

function formatPrintScopeTemplate(template: string, vars: Record<string, string | number>): string {
  return template.replace(/\{(\w+)\}/g, (_, key: string) => String(vars[key] ?? ''));
}

export function ServerPagedAggregateReportShell<T>({
  testIdPrefix,
  pageId,
  title,
  listTitle,
  titleIconClass,
  emptyMessage,
  filterItems,
  items,
  totalCount,
  page,
  pageSize,
  hasApplied,
  loading,
  pageLoading = false,
  onRefresh,
  onPageChange,
  onPageSizeChange,
  onConfigSaved,
  printFilterLines,
  allowedCharts,
  reportChartData,
  chartLabels,
  configLabels,
  fetchPrintPage,
  listRowMenuHelp = false,
  children,
}: ServerPagedAggregateReportShellProps<T>): React.ReactElement {
  const [configOpen, setConfigOpen] = useState(false);
  const [chartOpen, setChartOpen] = useState(false);
  const [printModalOpen, setPrintModalOpen] = useState(false);
  const [printLoading, setPrintLoading] = useState(false);
  const [printRowsOverride, setPrintRowsOverride] = useState<T[] | null>(null);
  const [printScopeLine, setPrintScopeLine] = useState<ReportPrintFilterLine | null>(null);
  const [displayConfig, setDisplayConfig] = useState<ErpReportDisplayConfig>(() =>
    loadErpReportDisplayConfig(testIdPrefix),
  );

  const busy = loading || pageLoading;
  const { showTableLoading } = useCatalogTableBusy(busy);
  const footerPagination = displayConfig.showFooterPagination && pageSize > 0;

  const visibleCharts = useMemo(() => {
    if (!isReportChartsEnabled(displayConfig.chart)) return [];
    return resolveReportCharts(allowedCharts, displayConfig.chart);
  }, [allowedCharts, displayConfig.chart]);

  const canShowCharts =
    totalCount > 0
    && visibleCharts.length > 0
    && reportChartData != null
    && reportChartData.summary.entryCount > 0;

  const displayRows = printRowsOverride ?? items;
  const sttPage = printRowsOverride ? 1 : page;
  const sttPageSize = printRowsOverride ? Math.max(printRowsOverride.length, 1) : pageSize;

  const showAllPagesPrintOption = footerPagination && totalCount > items.length;

  const handleSaveDisplayConfig = useCallback((next: ErpReportDisplayConfig) => {
    onConfigSaved?.(next, displayConfig);
    setDisplayConfig(next);
    saveErpReportDisplayConfig(testIdPrefix, next);
  }, [displayConfig, onConfigSaved, testIdPrefix]);

  const handleOpenChart = useCallback(() => {
    if (!canShowCharts) return;
    setChartOpen(true);
  }, [canShowCharts]);

  const handlePrint = useCallback(() => {
    if (!hasApplied || totalCount === 0 || showTableLoading || printLoading) return;
    if (showAllPagesPrintOption) {
      setPrintModalOpen(true);
      return;
    }
    runErpReportPrintAfterPaint(() => {
      setPrintRowsOverride(items);
      setPrintScopeLine(null);
    }, () => {
      setPrintRowsOverride(null);
      setPrintScopeLine(null);
    });
  }, [hasApplied, totalCount, showTableLoading, printLoading, showAllPagesPrintOption, items]);

  const handlePrintScopeConfirm = useCallback(async (scope: ReportPrintScope) => {
    if (!hasApplied || showTableLoading) return;
    setPrintLoading(true);
    try {
      if (scope === 'allPages') {
        const rowsForPrint = await fetchReportPagesInBatches({
          totalCount,
          batchSize: displayConfig.printFetchBatchSize,
          fetchPage: fetchPrintPage,
        });
        const scopeLine: ReportPrintFilterLine = {
          label: configLabels.printScopeFilterLabel,
          value: formatPrintScopeTemplate(configLabels.printScopeAllValue, { total: totalCount }),
        };
        setPrintModalOpen(false);
        runErpReportPrintAfterPaint(() => {
          setPrintRowsOverride(rowsForPrint);
          setPrintScopeLine(scopeLine);
        }, () => {
          setPrintRowsOverride(null);
          setPrintScopeLine(null);
        });
      } else {
        const scopeLine: ReportPrintFilterLine = {
          label: configLabels.printScopeFilterLabel,
          value: formatPrintScopeTemplate(configLabels.printScopeCurrentValue, {
            page,
            count: items.length,
          }),
        };
        setPrintModalOpen(false);
        runErpReportPrintAfterPaint(() => {
          setPrintRowsOverride(items);
          setPrintScopeLine(scopeLine);
        }, () => {
          setPrintRowsOverride(null);
          setPrintScopeLine(null);
        });
      }
    } finally {
      setPrintLoading(false);
    }
  }, [
    hasApplied,
    showTableLoading,
    totalCount,
    displayConfig.printFetchBatchSize,
    fetchPrintPage,
    configLabels,
    page,
    items,
  ]);

  const canPrint = hasApplied && totalCount > 0 && !showTableLoading && !printLoading;

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix,
      onRefresh,
      canChart: canShowCharts,
      onChart: handleOpenChart,
      canPrint,
      onPrint: handlePrint,
      onEditConfig: () => setConfigOpen(true),
    }),
    [testIdPrefix, onRefresh, canShowCharts, handleOpenChart, canPrint, handlePrint],
  );

  const printLines = useMemo(
    () => (printScopeLine ? [...printFilterLines, printScopeLine] : printFilterLines),
    [printFilterLines, printScopeLine],
  );

  const listBody = !showTableLoading && totalCount === 0 ? (
    <div className={erp.empty} data-testid={`${testIdPrefix}-empty`}>{emptyMessage}</div>
  ) : !showTableLoading ? (
    <>
      {hasApplied ? (
        <ReportPrintSummary title={title} filters={printLines} testIdPrefix={testIdPrefix} />
      ) : null}
      {children(displayRows, {
        rowNo: (index: number) => clientReportRowNo(index, sttPage, sttPageSize),
        onPrint: handlePrint,
        onChart: handleOpenChart,
        canChart: canShowCharts,
      })}
    </>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${testIdPrefix}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={testIdPrefix}
        pageId={pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title,
          titleIconClass,
          pageId,
        }}
        reportToolbar={reportToolbar}
        listTitle={listTitle}
        listRowMenuHelp={listRowMenuHelp}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          footerPagination && totalCount > 0 ? (
            <VoucherListPagination
              testIdPrefix={testIdPrefix}
              page={page}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={onPageChange}
              onPageSizeChange={size => onPageSizeChange(size as ListPageSize)}
            />
          ) : undefined
        }
        modals={(
          <>
            <LinReportTableConfigModal
              isOpen={configOpen}
              onClose={() => setConfigOpen(false)}
              testIdPrefix={testIdPrefix}
              config={displayConfig}
              chartCatalog={allowedCharts}
              onSave={handleSaveDisplayConfig}
              title={configLabels.configModalTitle}
              sectionGridLabel={configLabels.configSectionGrid}
              sectionFooterLabel={configLabels.configSectionFooter}
              sectionPrintLabel={configLabels.configSectionPrint}
              printBatchSizeLabel={configLabels.configPrintBatchSizeLabel}
              printBatchSizeHint={configLabels.configPrintBatchSizeHint}
              sectionChartLabel={configLabels.configSectionChart}
              chartEmptyHint={configLabels.configChartEmptyHint}
            />
            <LinReportPrintScopeModal
              isOpen={printModalOpen}
              onClose={() => setPrintModalOpen(false)}
              onConfirm={handlePrintScopeConfirm}
              printing={printLoading}
              testIdPrefix={testIdPrefix}
              currentPage={page}
              currentPageRowCount={items.length}
              totalCount={totalCount}
              showAllPagesOption={showAllPagesPrintOption}
              labels={{
                title: configLabels.printModalTitle,
                scopeLabel: configLabels.printScopeLabel,
                currentPageOption: configLabels.printCurrentPageOption,
                allPagesOption: configLabels.printAllPagesOption,
                cancel: configLabels.printCancel,
                confirm: configLabels.printConfirm,
                fetchHint: configLabels.printFetchHint,
              }}
            />
            <LedgerReportChartModal
              isOpen={chartOpen}
              onClose={() => setChartOpen(false)}
              items={[]}
              allowedCharts={visibleCharts}
              chartData={reportChartData ?? undefined}
              showKpiStrip={displayConfig.chart.showKpiStrip}
              filterLines={printFilterLines}
              labels={chartLabels}
              testIdPrefix={testIdPrefix}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
}
