import { openWorkspaceTab } from './openWorkspaceTab';

export type OpenSourceDocumentViewInput = {
  /** BE SSOT — platform path (`/kt/pt/{id}`, `/kho/pnk/{id}`, …). */
  sourceDocumentViewUrl: string;
  title: string;
  returnPath: string;
  returnTitle?: string;
  documentType?: string | null;
  navigate: (path: string) => void;
};

/** Open source document full page from BE `sourceDocumentViewUrl` — cross-MFE via shell tabs. */
export function openSourceDocumentView(input: OpenSourceDocumentViewInput): void {
  const {
    sourceDocumentViewUrl,
    title,
    returnPath,
    returnTitle,
    documentType,
    navigate,
  } = input;
  if (!sourceDocumentViewUrl.trim()) return;

  openWorkspaceTab(
    {
      path: sourceDocumentViewUrl,
      title,
      returnPath,
      returnTitle,
      documentType: documentType ?? undefined,
    },
    navigate,
  );
}

export type ReportRowSourceDocumentFields = {
  sourceDocumentViewUrl?: string | null;
  sourceDocumentType?: string | null;
  canOpenSourceDocument?: boolean;
};

export function resolveSourceDocumentViewUrl(row: ReportRowSourceDocumentFields): string | null {
  const fromBe = row.sourceDocumentViewUrl?.trim();
  if (fromBe) return fromBe;
  return null;
}

export function canOpenSourceDocumentRow(row: ReportRowSourceDocumentFields | null | undefined): boolean {
  if (!row?.canOpenSourceDocument) return false;
  return Boolean(resolveSourceDocumentViewUrl(row));
}
